 namespace WPAICG\AutoGPT\Ajax\Actions\SaveTask; use WP_Error; if (!defined('ABSPATH')) { exit; } function save_task_to_database_logic(string $task_name, string $task_type, array $task_config, string $task_status, int $task_id): int|WP_Error { global $wpdb; $tasks_table_name = $wpdb->prefix . 'aipkit_automated_tasks'; $data = [ 'task_name' => $task_name, 'task_type' => $task_type, 'task_config' => wp_json_encode($task_config), 'status' => $task_status, 'updated_at' => current_time('mysql', 1), ]; $formats = ['%s', '%s', '%s', '%s', '%s']; if ($task_id > 0) { $result = $wpdb->update($tasks_table_name, $data, ['id' => $task_id], $formats, ['%d']); if ($result === false) { return new WP_Error('db_error_update_task', __('Failed to update task.', 'gpt3-ai-content-generator'), ['status' => 500]); } return $task_id; } else { $data['created_at'] = current_time('mysql', 1); $formats[] = '%s'; $result = $wpdb->insert($tasks_table_name, $data, $formats); if ($result === false) { return new WP_Error('db_error_insert_task', __('Failed to save new task.', 'gpt3-ai-content-generator'), ['status' => 500]); } return $wpdb->insert_id; } } 